import { useNavigate, useParams } from "react-router-dom";
import { useState, useEffect, useRef } from "react";
import axios from "axios";

const ServicesByCentreLayer = () => {
  const { id } = useParams();
  const navigate = useNavigate();

  const [services, setServices] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [selectedService, setSelectedService] = useState(null);

  // Pagination state
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalServices, setTotalServices] = useState(0);
  const [loading, setLoading] = useState(false);
  const recordsPerPage = 8;

  // Calculate index for serial numbers
  const indexOfFirstRecord = (currentPage - 1) * recordsPerPage;

  // Create a ref for the modal
  const modalRef = useRef(null);

  const fetchServices = async (page = 1) => {
    try {
      setLoading(true);
      const response = await axios.get(
        `${process.env.REACT_APP_BACKEND_URL}/api/centreService/${id}`,
        {
          params: {
            page: page,
            limit: recordsPerPage
          }
        }
      );

      // Handle paginated response
      if (response.data.services) {
        setServices(response.data.services);
        setCurrentPage(response.data.currentPage || page);
        setTotalPages(response.data.totalPages || 1);
        setTotalServices(response.data.totalServices || 0);
      }
    } catch (error) {
      console.error("Error fetching services:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (id) {
      fetchServices(1);
    }
  }, [id]);

  // Handle clicks outside the modal
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (modalRef.current && !modalRef.current.contains(event.target) && showModal) {
        setShowModal(false);
      }
    };

    document.addEventListener("mousedown", handleClickOutside);

    // Scroll lock logic
    if (showModal) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "auto";
    }

    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
      document.body.style.overflow = "auto";
    };
  }, [showModal]);

  const handleViewDetails = (service) => {
    setSelectedService(service);
    setShowModal(true);
  };

  const handlePageChange = (newPage) => {
    if (newPage >= 1 && newPage <= totalPages) {
      setCurrentPage(newPage);
      fetchServices(newPage);
      window.scrollTo({ top: 0, behavior: "smooth" });
    }
  };

  const handlePageChangeWithScroll = (page) => {
    handlePageChange(page);
  };

  const renderPagination = () => {
    const pages = [];
    const maxVisible = 3;
    let startPage = Math.max(1, currentPage - Math.floor(maxVisible / 2));
    let endPage = startPage + maxVisible - 1;

    if (endPage > totalPages) {
      endPage = totalPages;
      startPage = Math.max(1, endPage - maxVisible + 1);
    }

    pages.push(
      <li
        key="first"
        className={`page-item ${currentPage === 1 ? " disabled" : ""}`}
      >
        <button
          className="page-link"
          onClick={() => currentPage !== 1 && handlePageChangeWithScroll(1)}
        >
          First
        </button>
      </li>
    );

    // Prev Button
    pages.push(
      <li
        key="prev"
        className={`page-item ${currentPage === 1 ? "disabled" : ""}`}
      >
        <button
          className="page-link"
          onClick={() =>
            currentPage > 1 && handlePageChangeWithScroll(currentPage - 1)
          }
        >
          Prev
        </button>
      </li>
    );

    // Page Numbers
    for (let i = startPage; i <= endPage; i++) {
      pages.push(
        <li
          key={i}
          className={`page-item ${currentPage === i ? "active" : ""}`}
        >
          <button
            className="page-link"
            onClick={() => handlePageChangeWithScroll(i)}
          >
            {i}
          </button>
        </li>
      );
    }

    // Next Button
    pages.push(
      <li
        key="next"
        className={`page-item ${
          currentPage === totalPages ? "disabled" : ""
        }`}
      >
        <button
          className="page-link"
          onClick={() =>
            currentPage < totalPages &&
            handlePageChangeWithScroll(currentPage + 1)
          }
        >
          Next
        </button>
      </li>
    );

    pages.push(
      <li
        key="last"
        className={`page-item ${currentPage === totalPages ? "disabled" : ""}`}
      >
        <button
          className="page-link"
          onClick={() => handlePageChangeWithScroll(totalPages)}
        >
          Last
        </button>
      </li>
    );

    return pages;
  };

  return (
    <div className="dashboard-body__content">
      {/* Service List */}
      <div className="card common-card border border-gray-five">
        <div className="card-body">
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <h2 className="mb-3">
              Available Services {totalServices > 0 && `(${totalServices})`}
            </h2>
            {totalServices > 0 && (
              <span className="text-muted">
                Page {currentPage} of {totalPages}
              </span>
            )}
          </div>

          {loading ? (
            <div className="text-center py-5">
              <div className="spinner-border text-primary" role="status">
                <span className="visually-hidden">Loading...</span>
              </div>
              <p className="mt-2">Loading services...</p>
            </div>
          ) : services.length > 0 ? (
            <>
              <div className="table-responsive">
                <table className="table text-body">
                  <thead>
                    <tr>
                      <th>SN.</th>
                      <th>Category</th>
                      <th>Service Name</th>
                      <th>Price</th>
                      <th>Doctors</th>
                      <th>Shift Times</th>
                      <th>Description</th>
                      <th>Action</th>
                    </tr>
                  </thead>
                  <tbody>
                    {services.map((service, index) => (
                      <tr key={service._id}>
                        <td>{indexOfFirstRecord + index + 1}</td>
                        <td>{service.serviceCategory}</td>
                        <td>{service.serviceName}</td>
                        <td style={{ textAlign: "left" }}>₹{service.totalPrice}</td>
                        <td style={{ textAlign: "left" }}>
                          {service?.doctors?.slice(0, 3).map((doc, i) => (
                            <div key={i}>
                              {doc?.name}
                              {i === 2 && service.doctors?.length > 3 && (
                                <span
                                  style={{
                                    fontSize: "12px",
                                    color: "blue",
                                    cursor: "pointer",
                                    marginLeft: "8px",
                                    textDecoration: "underline",
                                  }}
                                  onClick={() => handleViewDetails(service)}
                                >
                                  View More
                                </span>
                              )}
                            </div>
                          ))}
                          {(!service.doctors || service.doctors.length === 0) && (
                            <span className="text-muted">No doctors</span>
                          )}
                        </td>
                        <td style={{ textAlign: "left" }}>
                          {service?.slots?.slice(0, 3).map((slot, i) => (
                            <div key={i}>
                              {slot?.day?.slice(0, 3)}: {slot?.from} - {slot?.to}
                            </div>
                          ))}
                          {service.slots?.length > 3 && (
                            <span
                              style={{
                                fontSize: "12px",
                                color: "blue",
                                cursor: "pointer",
                                marginLeft: "8px",
                                textDecoration: "underline",
                              }}
                              onClick={() => handleViewDetails(service)}
                            >
                              View More
                            </span>
                          )}
                          {(!service.slots || service.slots.length === 0) && (
                            <span className="text-muted">No slots</span>
                          )}
                        </td>
                        <td
                          style={{
                            maxWidth: "300px",
                            overflow: "hidden",
                            whiteSpace: "nowrap",
                            textOverflow: "ellipsis",
                          }}
                        >
                          {service.description || "No description"}
                        </td>
                        <td>
                          <button
                            onClick={() => {
                              setSelectedService(service);
                              setShowModal(true);
                            }}
                            style={{
                              backgroundColor: "#007bff",
                              color: "white",
                              border: "none",
                              borderRadius: "4px",
                              padding: "5px 10px",
                              marginRight: "5px",
                              cursor: "pointer",
                            }}
                          >
                            View
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>

              {/* Pagination Controls */}
              {totalPages > 1 && (
                <nav aria-label="Services pagination" className="mt-3">
                  <ul className="pagination justify-content-center">
                    {renderPagination()}
                  </ul>
                </nav>
              )}
            </>
          ) : (
            <p className="text-muted text-center py-4">No services added yet.</p>
          )}
        </div>
      </div>

      {/* Modal */}
      {showModal && selectedService && (
        <div
          style={{
            position: "fixed",
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: "rgba(0,0,0,0.5)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            zIndex: 1000,
          }}
          onClick={() => setShowModal(false)}
        >
          <div
            ref={modalRef}
            style={{
              backgroundColor: "#fff",
              borderRadius: "10px",
              maxWidth: "700px",
              width: "90%",
              boxShadow: "0 0 10px rgba(0,0,0,0.3)",
              position: "relative",
              overflow: "hidden",
              maxHeight: "90vh",
              overflowY: "auto",
            }}
            onClick={(e) => e.stopPropagation()}
          >
            {/* Modal Header */}
            <div
              style={{
                backgroundColor: "#3a3a3a",
                color: "#fff",
                padding: "15px 20px",
                fontSize: "18px",
                fontWeight: "bold",
                position: "sticky",
                top: 0,
                zIndex: 10,
              }}
            >
              {selectedService.serviceName}
              <button
                onClick={() => setShowModal(false)}
                style={{
                  position: "absolute",
                  top: "10px",
                  right: "10px",
                  background: "transparent",
                  border: "none",
                  fontSize: "22px",
                  color: "#fff",
                  cursor: "pointer",
                }}
              >
                &times;
              </button>
            </div>

            {/* Modal Body */}
            <div
              style={{
                display: "flex",
                padding: "20px",
                flexWrap: "wrap",
                gap: "20px",
              }}
            >
              <div style={{ flex: "1", minWidth: "250px" }}>
                <div style={{ marginBottom: "20px" }}>
                  <p>
                    <strong style={{ color: "black" }}>Category</strong>
                  </p>
                  <p>{selectedService.serviceCategory}</p>
                </div>
                <div style={{ marginBottom: "20px" }}>
                  <p>
                    <strong style={{ color: "black" }}>Price</strong>
                  </p>
                  <p>₹{selectedService.totalPrice}</p>
                </div>
                <div style={{ marginBottom: "20px" }}>
                  <p>
                    <strong style={{ color: "black" }}>Description</strong>
                  </p>
                  <p>{selectedService.description || "No description"}</p>
                </div>
              </div>

              <div style={{ flex: "1", minWidth: "250px" }}>
                <div style={{ marginBottom: "20px" }}>
                  <p>
                    <strong style={{ color: "black" }}>Doctors</strong>
                  </p>
                  {selectedService.doctors?.length > 0 ? (
                    <ul>
                      {selectedService.doctors.map((doc, i) => (
                        <li key={i}>{doc?.name || "Unknown"}</li>
                      ))}
                    </ul>
                  ) : (
                    <p className="text-muted">No doctors assigned</p>
                  )}
                </div>
                <div style={{ marginBottom: "20px" }}>
                  <p>
                    <strong style={{ color: "black" }}>Shift Times</strong>
                  </p>
                  {selectedService.slots?.length > 0 ? (
                    <ul>
                      {selectedService.slots.map((slot, i) => (
                        <li key={i}>
                          {slot.day}: {slot.from} - {slot.to}
                        </li>
                      ))}
                    </ul>
                  ) : (
                    <p className="text-muted">No slots available</p>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ServicesByCentreLayer;